/**
 * Wink A/B Testing Tracker
 * ~3KB gzipped
 */
(function(window, document) {
    'use strict';

    var Wink = window.Wink || {};
    var config = window._winkConfig || {};
    var queue = [];
    var flushTimer = null;
    var endpoint = config.endpoint || '/wink/track';
    var batchInterval = (config.batchInterval || 5) * 1000;

    // Check Do Not Track
    function isDnt() {
        return navigator.doNotTrack === '1' || window.doNotTrack === '1';
    }

    if (config.respectDnt && isDnt()) {
        Wink.convert = function() {};
        Wink.track = function() {};
        window.Wink = Wink;
        return;
    }

    /**
     * Queue an event for batched sending.
     */
    function queueEvent(data) {
        queue.push(data);
        if (!flushTimer) {
            flushTimer = setTimeout(flush, batchInterval);
        }
    }

    /**
     * Flush queued events to the server.
     */
    function flush() {
        if (queue.length === 0) return;

        var events = queue.splice(0, queue.length);
        flushTimer = null;

        var xhr = new XMLHttpRequest();
        xhr.open('POST', endpoint, true);
        xhr.setRequestHeader('Content-Type', 'application/json');
        xhr.setRequestHeader('Accept', 'application/json');
        xhr.send(JSON.stringify({ events: events }));

        // GA4 forwarding
        if (config.enableGa4 && typeof gtag === 'function') {
            events.forEach(function(evt) {
                gtag('event', evt.type === 'conversion' ? 'wink_conversion' : 'wink_impression', {
                    experiment: evt.experiment,
                    variant: evt.variant,
                    goal: evt.goal || undefined
                });
            });
        }

        // GTM dataLayer forwarding
        if (config.enableGtm && window.dataLayer) {
            events.forEach(function(evt) {
                window.dataLayer.push({
                    event: config.gtmEventName || 'wink_experiment',
                    winkExperiment: evt.experiment,
                    winkVariant: evt.variant,
                    winkEventType: evt.type,
                    winkGoal: evt.goal || undefined
                });
            });
        }
    }

    /**
     * Track an impression for an experiment.
     */
    Wink.track = function(experimentHandle, variantHandle) {
        queueEvent({
            experiment: experimentHandle,
            variant: variantHandle,
            type: 'impression',
            url: window.location.href,
            referrer: document.referrer || null
        });
    };

    /**
     * Record a conversion.
     */
    Wink.convert = function(goalHandle, metadata) {
        // Find experiments from data attributes on the page
        var experiments = document.querySelectorAll('[data-wink-experiment]');
        experiments.forEach(function(el) {
            var experimentHandle = el.getAttribute('data-wink-experiment');
            var variantHandle = el.getAttribute('data-wink-variant');

            queueEvent({
                experiment: experimentHandle,
                variant: variantHandle,
                type: 'conversion',
                goal: goalHandle,
                url: window.location.href,
                metadata: metadata || null
            });
        });

        // If no experiments on page, send without variant info
        if (experiments.length === 0 && goalHandle) {
            queueEvent({
                type: 'conversion',
                goal: goalHandle,
                url: window.location.href,
                metadata: metadata || null
            });
        }
    };

    /**
     * Auto-track impressions for elements with data-wink-experiment attribute.
     */
    function autoTrack() {
        var experiments = document.querySelectorAll('[data-wink-experiment]');
        experiments.forEach(function(el) {
            var experimentHandle = el.getAttribute('data-wink-experiment');
            var variantHandle = el.getAttribute('data-wink-variant');
            if (experimentHandle && variantHandle) {
                Wink.track(experimentHandle, variantHandle);
            }
        });
    }

    // Auto-track click goals
    function initClickTracking() {
        var goals = config.clickGoals || [];
        goals.forEach(function(goal) {
            var elements = document.querySelectorAll(goal.selector);
            elements.forEach(function(el) {
                el.addEventListener('click', function() {
                    Wink.convert(goal.handle);
                });
            });
        });
    }

    // Flush on page unload
    function onUnload() {
        if (queue.length > 0 && navigator.sendBeacon) {
            navigator.sendBeacon(endpoint, JSON.stringify({ events: queue }));
            queue = [];
        }
    }

    // Initialize
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', function() {
            autoTrack();
            initClickTracking();
        });
    } else {
        autoTrack();
        initClickTracking();
    }

    window.addEventListener('beforeunload', onUnload);
    window.addEventListener('pagehide', onUnload);

    // Force flush after batch interval even without new events
    setInterval(function() {
        if (queue.length > 0) flush();
    }, batchInterval);

    window.Wink = Wink;

})(window, document);
